import React, { useState, useEffect, useCallback } from 'react';
import TableTemplate from '../components/TableTemplate';
import FormTemplate from '../components/FormTemplate';
import SearchComponent from '../components/SearchComponent';
import { vehicleService } from '../api/vehicleService'; // ONLY CHANGE HERE

function VehiclePage() {
  const service = vehicleService;

  const [data, setData] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [isEditing, setIsEditing] = useState(false);
  const [currentEntity, setCurrentEntity] = useState(service.initialFormState);
  const [currentId, setCurrentId] = useState(null);
  const [authorities, setAuthorities] = useState([]);

  const fetchData = useCallback(async () => {
    setLoading(true);
    setError(null);
    try {
      const records = await service.getAll();
      setData(records);

      const authorityResponse = await fetch('http://localhost:3000/authority');
      const authorityData = await authorityResponse.json();
      setAuthorities(authorityData);
    } catch (err) {
      setError(`Failed to fetch ${service.name} data.`);
      console.error(err);
    } finally {
      setLoading(false);
    }
  }, [service]);

  useEffect(() => {
    fetchData();
  }, [fetchData]);

  const handleSave = async (formData, isEditMode, id) => {
    try {
      if (formData.Authority_ID && formData.Authority_ID !== '') {
        const authorityExists = authorities.some(authority => 
          authority.Authority_ID === parseInt(formData.Authority_ID)
        );
        if (!authorityExists) {
          setError(`Authority ID ${formData.Authority_ID} does not exist. Please enter a valid Authority ID or leave empty.`);
          return;
        }
      }

      setError(null);

      if (isEditMode) {
        await service.update(id, formData);
      } else {
        await service.add(formData); 
      }
      fetchData(); 
      handleCancelEdit();
    } catch (err) {
      let errorMessage = `Failed to ${isEditMode ? 'update' : 'add'} ${service.name} record.`;

      if (err.response?.data?.message) {
        if (err.response.data.message.includes('foreign key constraint')) {
          errorMessage = `Invalid Authority ID. The Authority_ID field must reference an existing Authority ID or be empty.`;
        } else {
          errorMessage = err.response.data.message;
        }
      } else if (err.message) {
        errorMessage = err.message;
      }

      setError(errorMessage);
      console.error(err);
    }
  };

  const handleDelete = async (id) => {
    if (!window.confirm(`Are you sure you want to delete ${service.name} ID ${id}?`)) return;
    try {
      await service.remove(id);
      fetchData();
    } catch (err) {
      setError(`Failed to delete ${service.name} record. Check for dependent records.`);
      console.error(err);
    }
  };

  const handleEdit = (item) => {
    setIsEditing(true);
    let itemData = { ...item };
    if (itemData.Installation_Date) {
      itemData.Installation_Date = new Date(itemData.Installation_Date).toISOString().split('T')[0];
    }
    setCurrentEntity(itemData);
    setCurrentId(item[service.entityIdKey]);
  };

  const handleCancelEdit = () => {
    setIsEditing(false);
    setCurrentEntity(service.initialFormState);
    setCurrentId(null);
  };

  // 🚛 Refined modern style (red accent theme)
  const pageStyles = {
    background: 'rgba(255, 255, 255, 0.95)',
    backdropFilter: 'blur(20px)',
    borderRadius: '24px',
    padding: '40px',
    margin: '20px 0',
    boxShadow: '0 20px 60px rgba(220,53,69,0.2), 0 10px 30px rgba(220,53,69,0.1)',
    border: '2px solid rgba(220,53,69,0.3)',
    position: 'relative',
    overflow: 'hidden',
  };

  const headerStyles = {
    textAlign: 'center',
    background: 'linear-gradient(135deg, #ff6a6a 0%, #dc3545 100%)',
    WebkitBackgroundClip: 'text',
    WebkitTextFillColor: 'transparent',
    fontSize: '3rem',
    fontWeight: '800',
    marginBottom: '30px',
    borderBottom: '4px solid transparent',
    borderImage: 'linear-gradient(90deg, #ff6a6a, #dc3545) 1',
    paddingBottom: '20px',
    letterSpacing: '0.5px',
  };

  const errorStyles = {
    background: 'linear-gradient(135deg, #f8d7da, #f5c6cb)',
    color: '#721c24',
    padding: '15px 20px',
    borderRadius: '12px',
    marginBottom: '25px',
    border: '1px solid #f5c6cb',
    fontSize: '1rem',
    fontWeight: '600',
  };

  const loadingStyles = {
    display: 'flex',
    justifyContent: 'center',
    alignItems: 'center',
    height: '300px',
    fontSize: '1.5rem',
    color: '#dc3545',
    fontWeight: '600',
  };

  if (loading)
    return (
      <div className="dashboard-page">
        <div style={loadingStyles}>
          <div style={{ textAlign: 'center' }}>
            <div style={{ fontSize: '2.5rem', marginBottom: '10px' }}>⏳</div>
            Loading {service.name} data...
          </div>
        </div>
      </div>
    );

  return (
    <div style={pageStyles}>
      <div style={headerStyles}>
        <div style={{ fontSize: '4rem', marginBottom: '10px' }}>🚛</div>
        <h2
          style={{
            margin: 0,
            fontSize: '3.2rem',
            fontWeight: '800',
            letterSpacing: '0.5px',
          }}
        >
          {service.name}
        </h2>
        <p
          style={{
            margin: '12px 0 0 0',
            fontSize: '1rem',
            color: '#dc3545',
            opacity: 0.85,
            fontWeight: '500',
          }}
        >
          Manage vehicle records and linked authorities efficiently
        </p>
      </div>

      {error && <div style={errorStyles}>⚠️ Error: {error}</div>}

      <SearchComponent 
        entityName={service.name} 
        entityIdKey={service.entityIdKey}
        onSearch={service.getOne} 
        onEdit={handleEdit}
        onDelete={handleDelete}
      />

      <FormTemplate
        fields={service.fields}
        initialData={currentEntity}
        onSave={handleSave}
        isEditing={isEditing}
        entityId={currentId}
        onCancelEdit={handleCancelEdit}
      />

      <h3
        style={{
          fontSize: '1.8rem',
          fontWeight: '700',
          textAlign: 'center',
          marginTop: '30px',
          marginBottom: '25px',
          background: 'linear-gradient(135deg, #ff6a6a 0%, #dc3545 100%)',
          WebkitBackgroundClip: 'text',
          WebkitTextFillColor: 'transparent',
        }}
      >
        📋 All {service.name} Records
      </h3>

      <TableTemplate
        data={data}
        columns={service.columns}
        entityIdKey={service.entityIdKey}
        onEdit={handleEdit}
        onDelete={handleDelete}
      />
    </div>
  );
}

export default VehiclePage;
